import React from 'react';
import { motion } from 'framer-motion';
import { Link } from 'react-scroll';
import { HiArrowRight, HiMail } from 'react-icons/hi';
import { FiGithub } from 'react-icons/fi';
import { stats } from '../data/portfolioData';

const container = {
  hidden: {},
  show: { transition: { staggerChildren: 0.12 } },
};

const item = {
  hidden: { opacity: 0, y: 24 },
  show: { opacity: 1, y: 0, transition: { duration: 0.65, ease: [0.22, 1, 0.36, 1] } },
};

export default function Hero() {
  return (
    <section
      id="hero"
      className="relative min-h-screen flex flex-col justify-center overflow-hidden"
      style={{
        background: `
          radial-gradient(ellipse 80% 60% at 10% 40%, rgba(108,99,255,0.10) 0%, transparent 60%),
          radial-gradient(ellipse 60% 50% at 90% 10%, rgba(56,189,248,0.07) 0%, transparent 55%),
          #0a0a0f
        `,
      }}
    >
      {/* Grid texture */}
      <div
        className="absolute inset-0 pointer-events-none"
        style={{
          backgroundImage:
            'linear-gradient(rgba(108,99,255,0.035) 1px, transparent 1px), linear-gradient(90deg, rgba(108,99,255,0.035) 1px, transparent 1px)',
          backgroundSize: '64px 64px',
        }}
      />

      {/* Glow blobs */}
      <div className="absolute top-1/3 left-[15%] w-80 h-80 rounded-full bg-[#6c63ff]/8 blur-[120px] pointer-events-none" />
      <div className="absolute top-[20%] right-[15%] w-64 h-64 rounded-full bg-[#38bdf8]/6 blur-[90px] pointer-events-none" />

      <div className="relative max-w-7xl mx-auto px-6 pt-28 pb-24 w-full">
        <motion.div variants={container} initial="hidden" animate="show" className="max-w-4xl">

          {/* Available badge */}
          <motion.div variants={item} className="mb-8">
            <span className="inline-flex items-center gap-2.5 px-3.5 py-1.5 rounded-full text-sm font-medium border border-emerald-500/25 bg-emerald-500/[0.08] text-emerald-400">
              <span className="relative flex h-2 w-2">
                <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-emerald-400 opacity-75" />
                <span className="relative inline-flex h-2 w-2 rounded-full bg-emerald-500" />
              </span>
              Available for full-time roles
            </span>
          </motion.div>

          {/* Name */}
          <motion.h1
            variants={item}
            className="font-space font-bold leading-[1.05] tracking-tight mb-5"
            style={{ fontSize: 'clamp(3rem, 8vw, 5.5rem)' }}
          >
            <span className="text-white">Hana </span>
            <br />
            <span className="bg-gradient-to-r from-[#6c63ff] via-[#a78bfa] to-[#38bdf8] bg-clip-text text-transparent">
              Al Haris
            </span>
          </motion.h1>

          {/* Role */}
          <motion.div variants={item} className="flex items-center gap-2 mb-5">
            <span className="font-mono text-[#6c63ff] text-xl select-none">{'>'}_</span>
            <p className="font-mono text-[#38bdf8]/90 text-base md:text-lg tracking-wide">
              AI/ML Engineer&nbsp;
              <span className="text-slate-600">|</span>&nbsp;
              GenAI &amp; Agentic Systems&nbsp;
              <span className="text-slate-600">|</span>&nbsp;
              FinTech AI
            </p>
          </motion.div>

          {/* Description */}
          <motion.p
            variants={item}
            className="text-slate-400 text-lg leading-relaxed max-w-2xl mb-10"
          >
            Building production-grade AI systems at the intersection of machine learning,
            agentic frameworks, and financial intelligence. From LangGraph multi-agent pipelines
            to AML detection engines — I ship systems that reason, adapt, and deliver.
          </motion.p>

          {/* CTA buttons */}
          <motion.div variants={item} className="flex flex-wrap gap-3 mb-16">
            <Link to="projects" smooth duration={500} offset={-64}>
              <button className="flex items-center gap-2 px-6 py-3 rounded-xl font-semibold text-white bg-gradient-to-r from-[#6c63ff] to-[#4f46e5] hover:from-[#7c74ff] hover:to-[#6054f6] shadow-lg shadow-[#6c63ff]/25 transition-all duration-200">
                View Projects <HiArrowRight />
              </button>
            </Link>
            <a href="mailto:hanaharis95@gmail.com">
              <button className="flex items-center gap-2 px-6 py-3 rounded-xl font-semibold text-slate-300 border border-white/10 bg-white/[0.04] hover:bg-white/[0.08] hover:text-white hover:border-white/20 transition-all duration-200">
                <HiMail /> Contact Me
              </button>
            </a>
            <a href="https://github.com/Hanah7511" target="_blank" rel="noopener noreferrer">
              <button className="flex items-center gap-2 px-6 py-3 rounded-xl font-semibold text-slate-300 border border-white/10 bg-white/[0.04] hover:bg-white/[0.08] hover:text-white hover:border-white/20 transition-all duration-200">
                <FiGithub /> GitHub
              </button>
            </a>
          </motion.div>

          {/* Stats */}
          <motion.div variants={item} className="grid grid-cols-2 sm:grid-cols-4 gap-4 max-w-2xl">
            {stats.map((s) => (
              <div
                key={s.label}
                className="px-4 py-4 rounded-2xl border border-white/[0.06] bg-white/[0.02] backdrop-blur-sm"
              >
                <div className="font-space text-3xl font-bold bg-gradient-to-br from-[#6c63ff] to-[#38bdf8] bg-clip-text text-transparent">
                  {s.value}
                </div>
                <div className="text-slate-500 text-xs mt-1 font-medium">{s.label}</div>
              </div>
            ))}
          </motion.div>
        </motion.div>
      </div>

      {/* Scroll hint */}
      <motion.div
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        transition={{ delay: 2.5 }}
        className="absolute bottom-8 left-1/2 -translate-x-1/2 flex flex-col items-center gap-1.5"
      >
        <span className="font-mono text-slate-600 text-[10px] uppercase tracking-widest">scroll</span>
        <motion.div
          animate={{ y: [0, 6, 0] }}
          transition={{ repeat: Infinity, duration: 1.8, ease: 'easeInOut' }}
          className="w-px h-8 bg-gradient-to-b from-[#6c63ff]/60 to-transparent"
        />
      </motion.div>
    </section>
  );
}
